from flask import Flask, request
from prometheus_client import Counter, generate_latest, CollectorRegistry
from prometheus_client.exposition import basic_auth_handler
from prometheus_client import make_wsgi_app

app = Flask(__name__)
registry = CollectorRegistry()

# Dictionary to hold counters for each unique user-path combination
counters = {}

@app.route('/metrics')
def metrics():
    return generate_latest(registry)

@app.before_request
def track_request():
    user_id = request.args.get('user_id')
    session_id = request.args.get('session_id')
    full_path = request.full_path

    if user_id and full_path:
        key = f"{user_id}_{full_path}"
        if key not in counters:
            counters[key] = Counter('http_requests_total', 'Total HTTP Requests', ['user_id', 'session_id', 'path'], registry=registry)
        
        counters[key].labels(user_id=user_id, session_id=session_id, path=full_path).inc()

if __name__ == '__main__':
    app.wsgi_app = make_wsgi_app(registry)
    app.run(host='0.0.0.0', port=5000)